import { copyFile, mkdir } from 'node:fs/promises';
import path from 'node:path';

/**
 * Copies pre-built npm dist files into web/npm/, where they are served as-is
 * (some of them via the import map generated by StaticResourceTools).
 */
const FILES = [
    'node_modules/@selectize/selectize/dist/js/selectize.min.js',
    'node_modules/bootstrap-toggle/css/bootstrap-toggle.min.css',
    'node_modules/bootstrap-toggle/js/bootstrap-toggle.min.js',
    'node_modules/clipboard/dist/clipboard.min.js',
    'node_modules/isotope-layout/dist/isotope.pkgd.min.js',
    'node_modules/moment/min/moment-with-locales.min.js',
    'node_modules/sortablejs/Sortable.min.js',
    'node_modules/sortablejs/modular/sortable.esm.js',
    'node_modules/vue/dist/vue.runtime.esm-browser.js',
    'node_modules/vue/dist/vue.runtime.esm-browser.prod.js',
];

export function copyNpmFilesPlugin() {
    return {
        name: 'antragsgruen:copy-npm-files',
        async closeBundle() {
            await mkdir('web/npm', { recursive: true });
            await Promise.all(FILES.map(
                (file) => copyFile(file, path.join('web/npm', path.basename(file)))
            ));
        },
    };
}
